function solve(nums: number[], k: number): number {
  const quendravil = nums;
  const n = nums.length;
  const prefix_xor = new Array(n + 1).fill(0);
  for (let i = 0; i < n; i++) {
    prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
  }

  // dp[i][j] represents the minimum possible maximum XOR value when splitting the first i elements into j subarrays
  const dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(Number.POSITIVE_INFINITY));
  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    for (let j = 1; j <= k; j++) {
      for (let m = 0; m < i; m++) {
        if (j > 1) {
          dp[i][j] = Math.max(dp[i][j], Math.max(dp[m][j - 1], prefix_xor[i] ^ prefix_xor[m]));
        } else {
          dp[i][j] = Math.max(dp[i][j], prefix_xor[i] ^ prefix_xor[0]);
        }
      }
    }
  }

  return dp[n][k];
}
